def predict(key, box) -> bool:
    # According to the teacher's demonstration: "use a key that matches the color of the box"
    # So the primary rule is color matching
    if key.color == box.color:
        return True

    # Additionally, check for shape matching: key.shape should match box.shape
    if key.shape is not None and key.shape == box.shape:
        return True

    # Also check for number matching: key.number should equal box.number
    if key.number is not None and key.number == box.number:
        return True

    return False

